func (r *RunEvery) Start() error {
	if r.started {
		return nil
	}

	r.started = true
	r.quit = make(chan struct{})

	go func() {
		if r.RunImmediately {
			r.run()
		}
		ticker := time.NewTicker(500 * time.Millisecond)
		defer ticker.Stop()
		for {
			select {
			case <-r.quit:
				return
			case <-ticker.C:
				r.run()
			}
		}
	}()

	return nil
}
